                    var resource = new ResourceDictionary
                    {
                        Source = new Uri("/AdaptiveCards.Rendering.Wpf;component/Themes/generic.xaml",
                       UriKind.RelativeOrAbsolute)
                    };
                    _resources.MergedDictionaries.Add(resource);
                }
                catch { }

                return _resources;
            }

